import React from 'react';
import { Trash2, Calendar, Tag } from 'lucide-react';

const ListaOfertas = ({ ofertas, onDelete }) => {
  if (ofertas.length === 0) {
    return (
      <div style={emptyStateStyle}>
        <Tag size={48} color="#cbd5e1" />
        <p>No hay ofertas publicadas para este local.</p>
      </div>
    );
  }

  return (
    <div style={gridStyle}>
      {ofertas.map((oferta) => (
        <div key={oferta.id} style={cardStyle}>
          <div style={badgeStyle}>Oferta</div>
          <h3 style={{ marginBottom: '5px' }}>{oferta.producto}</h3>
          <p style={precioStyle}>${oferta.precio}</p>
          <div style={infoStyle}>
            <Calendar size={14} /> <span>Vence: {oferta.vencimiento}</span>
          </div>
          {oferta.descripcion && <p style={descStyle}>{oferta.descripcion}</p>}
          
          <button onClick={() => onDelete(oferta.id)} style={btnDelete}>
            <Trash2 size={16} /> Eliminar
          </button>
        </div>
      ))}
    </div>
  );
};

/* --- ESTILOS --- */
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '20px' };
const cardStyle = { background: 'white', padding: '20px', borderRadius: '20px', border: '1px solid #e2e8f0', position: 'relative' };
const badgeStyle = { position: 'absolute', top: '20px', right: '20px', background: '#fef3c7', color: '#d97706', padding: '4px 10px', borderRadius: '20px', fontSize: '0.7rem', fontWeight: 'bold', textTransform: 'uppercase' };
const precioStyle = { fontSize: '1.8rem', fontWeight: '800', color: '#e67e22', margin: '10px 0' };
const infoStyle = { display: 'flex', alignItems: 'center', gap: '6px', color: '#64748b', fontSize: '0.85rem', marginBottom: '10px' };
const descStyle = { fontSize: '0.9rem', color: '#475569', borderTop: '1px solid #f1f5f9', paddingTop: '10px', marginTop: '10px' };
const btnDelete = { width: '100%', padding: '10px', marginTop: '15px', background: '#fff1f2', color: '#e11d48', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: '600', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' };
const emptyStateStyle = { textAlign: 'center', padding: '60px', background: 'white', borderRadius: '20px', border: '2px dashed #e2e8f0', color: '#64748b' };

export default ListaOfertas;
